+function parseUsingIdentOrDeclarationStatement(
+  parser: Parser,
+  context: Context,
+  scope: Scope | undefined,
+  privateScope: PrivateScope | undefined,
+  origin: Origin,
+): ESTree.VariableDeclaration | ESTree.ExpressionStatement {
+  const { tokenStart } = parser;
+  let expr: ESTree.Identifier | ESTree.Expression = parseIdentifier(parser, context);
+
+  if ((parser.flags & Flags.NewLine) === 0) {
+    return parseUsingDeclaration(parser, context, scope, privateScope, false, tokenStart);
+  }
+
+  expr = parseMemberOrUpdateExpression(parser, context, privateScope, expr, 0, 0, tokenStart);
+  expr = parseAssignmentExpression(parser, context, privateScope, 0, 0, tokenStart, expr as ESTree.ArgumentExpression);
+  if (parser.getToken() === Token.Comma) expr = parseSequenceExpression(parser, context, privateScope, 0, tokenStart, expr);
+  return parseExpressionStatement(parser, context, expr, tokenStart);
+}
+
+/** Parses `await using` at statement start, retaining ordinary await-expression behavior otherwise. */
+function parseAwaitUsingOrExpressionStatement(
+  parser: Parser,
+  context: Context,
+  scope: Scope | undefined,
+  privateScope: PrivateScope | undefined,
+  origin: Origin,
+): ESTree.VariableDeclaration | ESTree.ExpressionStatement {
+  const start = parser.tokenStart;
+  const awaitExpression = parseIdentifierOrArrow(parser, context, privateScope);
+
+  if (parser.getToken() === Token.UsingKeyword && (parser.flags & Flags.NewLine) === 0) {
+    return parseUsingDeclaration(parser, context, scope, privateScope, true, start);
+  }
+
+  const isIdentifier =
+    awaitExpression.type === 'ArrowFunctionExpression' || (parser.getToken() & Token.IsExpressionStart) === 0;
+  if (isIdentifier) {
+    if (context & Context.InAwaitContext) parser.report(Errors.InvalidAwaitAsIdentifier);
+    if (context & Context.Module) parser.report(Errors.AwaitIdentInModuleOrAsyncFunc);
+    return parseExpressionStatement(parser, context, awaitExpression, start);
+  }
+  if ((context & Context.InAwaitContext) === 0 && (context & Context.Module && context & Context.InGlobal) === 0) {
+    return parseExpressionStatement(parser, context, awaitExpression, start);
+  }
+  const argument = parseLeftHandSideExpression(parser, context, privateScope, 0, 0, 1);
+  const expr = parser.finishNode<ESTree.AwaitExpression>({ type: 'AwaitExpression', argument }, start);
+  return parseExpressionStatement(parser, context, expr, start);
+}
